INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'brightchamps', 'en', 'Teacher Coding Online', 'I have several years of experience as a software developer, tester, and automation developer. In parallel, I have supported and guided interns and clients throughout project development, explaining technical concepts and providing internal training when needed. I am proficient in Python, HTML/CSS/JavaScript, Dart, and Flutter. I am eager to join BrightChamps as an Online Coding Instructor to teach programming to students aged 6–16, delivering lessons that are clear, engaging, and effective.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'brightchamps', 'vi', 'Giáo viên Coding Online', 'Tôi có kinh nghiệm nhiều năm làm lập trình viên, tester và automation developer. Song song đó, tôi có kinh nghiệm hướng dẫn, hỗ trợ các bạn thực tập, khách hàng trong quá trình phát triển dự án, giải thích kỹ thuật, và đào tạo nội bộ. Tôi thành thạo Python, HTML/CSS/JS, Dart, Flutter. Tôi mong muốn trở thành Giáo viên Coding Online tại BrightChamps để giảng dạy lập trình cho học sinh 6–16 tuổi, mang đến trải nghiệm học tập dễ hiểu, vui vẻ và hiệu quả.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'data', 'en', 'Account Creation Staff', 'I am applying for the Account Creation Staff position, bringing carefulness, persistence, and a strong sense of responsibility to my work. With an IT background and freelance experience in programming and automation, I am capable of handling tasks accurately, efficiently, and in compliance with established processes. I am also learning more about MMO operations, giving me practical exposure to proxy, VPN, and related tools. If the company is interested, I am ready to discuss further. I believe I can quickly adapt to new tasks and perform well in this role.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'data', 'vi', 'Nhân viên tạo tài khoản', 'Tôi mong muốn ứng tuyển vị trí Nhân viên tạo tài khoản của công ty, với tinh thần cẩn thận, kiên trì và trách nhiệm trong công việc. Với nền tảng CNTT cùng kinh nghiệm làm việc tự do trong lĩnh vực lập trình và tự động hóa, tôi có khả năng xử lý thao tác nhanh, chính xác và tuân thủ quy trình. Hiện tại tôi cũng đang tìm hiểu thêm về MMO nên có kinh nghiệm tiếp xúc với proxy, VPN và một số công cụ hỗ trợ liên quan. Nếu công ty quan tâm, tôi rất sẵn sàng trao đổi thêm. Tôi tin rằng mình có thể thích ứng nhanh với công việc mới và hoàn thành tốt các nhiệm vụ được giao.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'freelancer-flutter', 'en', 'Flutter Developer', 'Flutter developer with 2 years of experience in building and developing cross-platform mobile applications. Proficient in state management using BLoC and Provider. Currently seeking remote opportunities where I can leverage my skills and programming mindset to effectively contribute to the company’s projects.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'freelancer-flutter', 'vi', 'Flutter Developer', 'Là một lập trình viên Flutter với 2 năm kinh nghiệm xây dựng và phát triển ứng dụng di động đa nền tảng. Thành thạo trong quản lý trạng thái bằng BLoC và Provider. Hiện tôi mong muốn tìm kiếm cơ hội làm việc remote, nơi tôi có thể tận dụng kinh nghiệm và tư duy lập trình để đóng góp hiệu quả vào các dự án của khách hàng.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'freelancer', 'en', 'Freelancer', 'As a freelancer, I am seeking additional stable opportunities to ensure long-term income. With a programming background, I am confident in my ability to successfully handle the tasks assigned by __COMPANY__.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'freelancer', 'vi', 'Freelancer', 'Là một freelancer, tôi mong muốn tìm kiếm thêm cơ hội làm việc ổn định để đảm bảo thu nhập lâu dài. Với nền tảng lập trình, tôi tự tin có thể thực hiện tốt công việc mà khách hàng đưa ra.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'mmo', 'en', 'Account Creation Staff', 'I am applying for the Account Creation Staff position, bringing carefulness, persistence, and a strong sense of responsibility to my work. With an IT background and freelance experience in programming and automation, I am capable of handling tasks accurately, efficiently, and in compliance with established processes. I am also learning more about MMO operations, giving me practical exposure to proxy, VPN, and related tools. If the company is interested, I am ready to discuss further. I believe I can quickly adapt to new tasks and perform well in this role.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'mmo', 'vi', 'Nhân viên tạo tài khoản', 'Tôi mong muốn ứng tuyển vị trí Nhân viên tạo tài khoản của công ty, với tinh thần cẩn thận, kiên trì và trách nhiệm trong công việc. Với nền tảng CNTT cùng kinh nghiệm làm việc trong lĩnh vực lập trình và tự động hóa, tôi có khả năng xử lý thao tác nhanh, chính xác và tuân thủ quy trình. Hiện tại tôi cũng đang tìm hiểu thêm về MMO nên có kinh nghiệm tiếp xúc với proxy, VPN và một số công cụ hỗ trợ liên quan. Nếu công ty quan tâm, tôi rất sẵn sàng trao đổi thêm. Tôi tin rằng mình có thể thích ứng nhanh với công việc mới và hoàn thành tốt các nhiệm vụ được giao.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'n8n', 'en', 'N8n Developer', 'I am applying for an n8n-related position, especially Automation Developer, leveraging my experience as a programmer and freelancer in mobile, web, automation, and AI, along with hands-on n8n exploration to build automated workflows, analyze processes, integrate APIs, optimize system performance, and support additional roles such as web/tool development or business analysis when needed.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'n8n', 'vi', 'N8n Developer', 'Tôi mong muốn ứng tuyển vào vị trí liên quan đến n8n, đặc biệt là Automation Developer. Với kinh nghiệm nhiều năm làm lập trình viên và freelancer trong các mảng mobile, web, automation và AI, cùng với việc đã tìm hiểu và thử nghiệm n8n trong các quy trình tự động hóa, tôi tin rằng mình có thể nhanh chóng thích ứng và đóng góp hiệu quả cho đội ngũ. Tôi có khả năng phân tích quy trình, xây dựng workflow tự động hóa, tích hợp API, mô phỏng hành vi người dùng và tối ưu hóa hiệu suất hệ thống. Bên cạnh đó, nền tảng kỹ thuật vững chắc giúp tôi có thể hỗ trợ thêm ở các vai trò xây dựng web/tool hoặc tham gia phân tích nghiệp vụ (BA) khi cần thiết.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'reikei', 'en', 'Flutter Developer', 'A Flutter developer with 2 years of experience in building and developing cross-platform mobile applications. Proficient in state management using BLoC and Provider, skilled in designing user-friendly UI/UX, optimizing performance, and delivering applications from concept to production. Experienced in working independently as well as collaborating in teams, familiar with remote workflows and flexible time management. Always ready to support clients’ projects with strong programming mindset, responsibility, and the drive to deliver high-quality products.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'reikei', 'vi', 'Flutter Developer', 'Là một Flutter với 2 năm kinh nghiệm xây dựng và phát triển ứng dụng di động đa nền tảng. Thành thạo trong quản lý trạng thái bằng BLoC và Provider, thiết kế UI/UX thân thiện, tối ưu hiệu năng và triển khai ứng dụng từ giai đoạn ý tưởng đến sản phẩm hoàn chỉnh. Có kinh nghiệm làm việc độc lập cũng như phối hợp trong nhóm, quen thuộc với quy trình làm việc remote và quản lý thời gian linh hoạt. Tôi luôn sẵn sàng hỗ trợ các dự án của khách hàng với tư duy lập trình chặt chẽ, tinh thần trách nhiệm và mong muốn tạo ra sản phẩm chất lượng.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'tester-game', 'en', 'Tester game', 'I am a mobile, web, and automation AI developer with experience testing crypto platforms and various games, and I’m eager to apply for a Game Tester role or any position where my skills can contribute.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'tester-game', 'vi', 'Tester game', 'Tôi mong muốn ứng tuyển vào vị trí Game Tester. Hiện tôi là một freelancer phát triển mobile, web, automation và AI, đồng thời có kinh nghiệm test thực tế trên các sàn giao dịch crypto và một số tựa game. Tôi có khả năng phân tích lỗi, kiểm thử tính năng, mô phỏng hành vi người dùng và đánh giá trải nghiệm sản phẩm. Bên cạnh kiến thức về lập trình và tự động hóa, tôi có tư duy logic, khả năng học nhanh và luôn sẵn sàng tiếp thu công nghệ mới. Tôi rất mong được gửi CV để công ty xem qua. Ngoài vị trí Game Tester, nếu công ty thấy tôi phù hợp với một vai trò khác, tôi cũng luôn sẵn lòng thử sức. Tôi tin rằng sự chủ động, kiên trì và nền tảng kỹ thuật của mình sẽ mang lại giá trị cho đội ngũ.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('fa120a82-c370-4eaf-a81a-42d834cad94f', 'tong-quan', 'en', 'Freelancer', 'Mobile developer with 2 years of experience in Flutter application development, committed to continuous learning, advancing technical expertise, and transforming innovative ideas into valuable products.');
INSERT INTO cv_variants (profile_id, slug, language, position, summary) VALUES ('b2ddfa86-bd1c-4552-8840-446d2414379f', 'tong-quan', 'vi', 'Freelancer', 'Là một lập trình viên mobile với 2 năm kinh nghiệm phát triển ứng dụng Flutter, mong muốn không ngừng học hỏi, nâng cao kỹ năng chuyên môn và hiện thực hóa những ý tưởng sáng tạo thành sản phẩm hữu ích.');
